import { encodeBase64Url } from './base64url.mjs';

const BLOB_ID_BYTES = 16;

export function formatBlobLocator({ bucket, id }) {
  if (typeof bucket !== 'string' || bucket.length === 0 || bucket.includes(':')) {
    throw new TypeError('bucket must be a non-empty name without a colon');
  }
  const bytes = Buffer.from(id);
  if (bytes.length !== BLOB_ID_BYTES) {
    throw new TypeError('blob id must contain 16 bytes');
  }
  return bucket + ':' + encodeBase64Url(bytes);
}

export function parseBlobLocator(text) {
  if (typeof text !== 'string') {
    throw new TypeError('blob locator must be a string');
  }
  const separator = text.indexOf(':');
  if (separator <= 0 || separator !== text.lastIndexOf(':')) {
    throw new TypeError('blob locator must contain one bucket separator');
  }

  const bucket = text.slice(0, separator);
  const encodedId = text.slice(separator + 1);
  const id = Buffer.from(encodedId, 'base64url');
  if (id.length !== BLOB_ID_BYTES) {
    throw new TypeError('blob id must contain 16 bytes');
  }
  return { bucket, id };
}

