import test from 'node:test';
import assert from 'node:assert/strict';
import { encodeBase64Url, decodeBase64Url } from '../src/base64url.mjs';
import { formatBlobLocator, parseBlobLocator } from '../src/blob-locator.mjs';

test('round trips a canonical unpadded base64url value', () => {
  const id = Buffer.from('00112233445566778899aabbccddeeff', 'hex');
  const encoded = encodeBase64Url(id);

  assert.equal(encoded, 'ABEiM0RVZneImaq7zN3u_w');
  assert.deepEqual(decodeBase64Url(encoded), id);
});

test('formats and parses an ordinary blob locator', () => {
  const id = Buffer.from('ffeeddccbbaa99887766554433221100', 'hex');
  const locator = formatBlobLocator({ bucket: 'images', id });

  assert.equal(locator, 'images:_-7dzLuqmYh3ZlVEMyIRAA');
  assert.deepEqual(parseBlobLocator(locator), { bucket: 'images', id });
});

test('rejects malformed locator structure and wrong id length', () => {
  assert.throws(() => parseBlobLocator('images'), /separator/);
  assert.throws(() => parseBlobLocator('images:AA'), /16 bytes/);
});
